+import { isRelationPair } from '../relation/utils/is-relation';
+import { addTrait, getTrait, hasTrait, removeTrait } from '../trait/trait';
+import type { ConfigurableTrait, ExtractSchema, Trait, TraitRecord } from '../trait/types';
+import type { World } from '../world/types';
+
+type Command =
+    | { type: 'spawn'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'destroy'; entity: Entity }
+    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[]; exclusive: boolean }
+    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] };
+
+type Scope = { commands: Command[] };
+type State = { scopes: Scope[]; flushing: boolean };
+
+export type DeferredWorld = {
+    spawn(...traits: ConfigurableTrait[]): Entity;
+    destroy(entity: Entity): void;
+    add(entity: Entity, ...traits: ConfigurableTrait[]): void;
+    remove(entity: Entity, ...traits: (Trait | RelationPair)[]): void;
+    addExclusive(entity: Entity, ...traits: ConfigurableTrait[]): void;
+    flush(): void;
+};
+
+const states = new WeakMap<World, State>();
+const stateFor = (world: World) => states.get(world)!;
+
+export function createDeferred(world: World): DeferredWorld {
+    states.set(world, { scopes: [{ commands: [] }], flushing: false });
+    const push = (command: Command) => stateFor(world).scopes.at(-1)!.commands.push(command);
+
+    return {
+        spawn(...traits) {
+            // Reserve a stable entity id without exposing it to queries until flush.
+            const index = world[$internal].entityIndex;
+            const entity = packEntity(index.worldId, 0, index.maxId++) as Entity;
+            push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) {
+            push({ type: 'destroy', entity });
+        },
+        add(entity, ...traits) {
+            push({ type: 'add', entity, traits, exclusive: false });
+        },
+        remove(entity, ...traits) {
+            push({ type: 'remove', entity, traits });
+        },
+        addExclusive(entity, ...traits) {
+            push({ type: 'add', entity, traits, exclusive: true });
+        },
+        flush() {
+            flushScope(world, stateFor(world).scopes[0]);
+        },
+    };
+}
+
+export function beginDeferredScope(world: World) {
+    stateFor(world).scopes.push({ commands: [] });
+}
+
+export function endDeferredScope(world: World) {
+    const state = stateFor(world);
+    const scope = state.scopes.pop()!;
+    flushScope(world, scope);
+}
+
+/** Flush commands touching one entity before an immediate mutation. */
+export function flushDeferredEntity(world: World, entity: Entity) {
+    const state = states.get(world);
+    if (!state || state.flushing) return;
+    for (const scope of state.scopes) {
+        const selected = scope.commands.filter((command) => command.entity === entity);
+        if (!selected.length) continue;
+        scope.commands = scope.commands.filter((command) => command.entity !== entity);
+        execute(world, selected);
+    }
+}
+
+export function hasDeferredTrait(world: World, entity: Entity, target: Trait | RelationPair): boolean | undefined {
+    const commands = commandsFor(world, entity);
+    if (!commands.length) return undefined;
+    let exists = isSpawned(commands) ? false : hasNow(world, entity, target);
+    for (const command of commands) {
+        if (command.type === 'destroy') return false;
+        if (command.type === 'spawn') continue;
+        for (const trait of command.type === 'add' ? command.traits : command.traits) {
+            if (!matches(target, trait)) continue;
+            exists = command.type === 'add';
+        }
+    }
+    return exists;
+}
+
+export function getDeferredTrait<T extends Trait | RelationPair>(
+    world: World,
+    entity: Entity,
+    target: T
+): TraitRecord<ExtractSchema<T>> | undefined | null {
+    const commands = commandsFor(world, entity);
+    if (!commands.length) return null;
+    let value = isSpawned(commands) ? undefined : getTrait(world, entity, target);
+    for (const command of commands) {
+        if (command.type === 'destroy') return undefined;
+        if (command.type !== 'add') continue;
+        for (const trait of command.traits) {
+            if (!matches(target, trait)) continue;
+            value = valueFor(trait) as TraitRecord<ExtractSchema<T>> | undefined;
+        }
+    }
+    return value;
+}
+
+function commandsFor(world: World, entity: Entity) {
+    const state = states.get(world);
+    return state ? state.scopes.flatMap((scope) => scope.commands.filter((c) => c.entity === entity)) : [];
+}
+function isSpawned(commands: Command[]) {
+    return commands.some((command) => command.type === 'spawn');
+}
+function hasNow(world: World, entity: Entity, target: Trait | RelationPair) {
+    return isRelationPair(target) ? entity.has(target) : hasTrait(world, entity, target);
+}
+function matches(target: Trait | RelationPair, config: ConfigurableTrait | Trait) {
+    if (isRelationPair(target) || isRelationPair(config)) {
+        return isRelationPair(target) && isRelationPair(config) &&
+            target[$internal].relation === config[$internal].relation &&
+            target[$internal].target === config[$internal].target;
+    }
+    const trait = Array.isArray(config) ? config[0] : config;
+    return target === trait;
+}
+function valueFor(config: ConfigurableTrait) {
+    if (isRelationPair(config)) return config[$internal].params;
+    return Array.isArray(config) ? config[1] : undefined;
+}
+
+function flushScope(world: World, scope: Scope) {
+    if (!scope.commands.length) return;
+    const commands = scope.commands;
+    scope.commands = [];
+    execute(world, commands);
+}
+
+function execute(world: World, commands: Command[]) {
+    const state = stateFor(world);
+    state.flushing = true;
+    try {
+        const cancelled = new Set<Entity>();
+        const spawns = new Set(commands.filter((c): c is Extract<Command, { type: 'spawn' }> => c.type === 'spawn').map((c) => c.entity));
+        for (const command of commands) {
+            if (command.type === 'destroy' && spawns.has(command.entity)) cancelled.add(command.entity);
+        }
+        for (const command of commands) {
+            if (cancelled.has(command.entity)) continue;
+            if (command.type === 'spawn') {
+                materializeEntity(world, command.entity, ...command.traits);
+            } else if (command.type === 'destroy') {
+                if (command.entity === world[$internal].worldEntity) {
+                    throw new Error('Koota: The world entity cannot be destroyed through deferred commands.');
+                }
+                if (world.has(command.entity)) destroyEntity(world, command.entity);
+            } else if (world.has(command.entity)) {
+                if (command.type === 'remove') {
+                    removeTrait(world, command.entity, ...command.traits);
+                } else {
+                    if (command.exclusive) {
+                        for (const trait of command.traits) {
+                            if (isRelationPair(trait)) removeTrait(world, command.entity, trait[$internal].relation('*'));
+                        }
+                    }
+                    addTrait(world, command.entity, ...command.traits);
+                }
+            }
+        }
+    } finally {
+        state.flushing = false;
+    }
+}
